	data, err := os.ReadFile("pkg/workflow/data/ecosystem_domains.json")
	if err != nil {
		panic(err)
	}
	var ecosystems map[string][]string
	if err := json.Unmarshal(data, &ecosystems); err != nil {
		panic(err)
	}
	javaDomains := ecosystems["java"]
	sort.Strings(javaDomains)
	fmt.Println("Java ecosystem domains:")
	for _, d := range javaDomains {
		fmt.Println("  ", d)
	}

	needle := []string{"maven-central.storage-download.googleapis.com", "repository.apache.org"}
