		found := false
		for _, d := range javaDomains {
			if d == n {
				found = true
				break
			}
		}
		if found {
			fmt.Printf("FOUND: %s\n", n)
		} else {
			fmt.Printf("MISSING: %s\n", n)
		}
	}
}
GOEOF

